#!/bin/bash
# MongoDB Sharding Status and Health Check
set -euo pipefail

MONGOS_PORT=27017

echo "=== Sharding Status ==="
mongosh --port "$MONGOS_PORT" --quiet --eval "sh.status()"

echo ""
echo "=== Shard Distribution ==="
mongosh --port "$MONGOS_PORT" --quiet --eval "
const dbs = db.adminCommand({listDatabases: 1}).databases;
dbs.forEach(d => {
  if (d.name !== 'admin' && d.name !== 'config' && d.name !== 'local') {
    print('--- ' + d.name + ' (' + Math.round(d.sizeOnDisk / 1024 / 1024) + 'MB) ---');
    const colls = db.getSiblingDB(d.name).getCollectionNames();
    colls.forEach(c => {
      const stats = db.getSiblingDB(d.name)[c].stats();
      if (stats.sharded) {
        print('  ' + c + ' (sharded): ' + stats.count + ' docs');
        Object.keys(stats.shards || {}).forEach(s => {
          print('    ' + s + ': ' + stats.shards[s].count + ' docs, ' +
            Math.round(stats.shards[s].size / 1024 / 1024) + 'MB');
        });
      }
    });
  }
});
"

echo ""
echo "=== Chunk Distribution ==="
mongosh --port "$MONGOS_PORT" --quiet --eval "
db.getSiblingDB('config').chunks.aggregate([
  {$group: {_id: {ns: '$ns', shard: '$shard'}, chunks: {$sum: 1}}},
  {$sort: {'_id.ns': 1, '_id.shard': 1}}
]).forEach(doc => {
  print(doc._id.ns + ' -> ' + doc._id.shard + ': ' + doc.chunks + ' chunks');
});
"

echo ""
echo "=== Balancer Status ==="
mongosh --port "$MONGOS_PORT" --quiet --eval "
const status = sh.getBalancerState();
print('Balancer enabled: ' + status);
const running = sh.isBalancerRunning();
print('Balancer running: ' + running);
"
